import{c as i,Q as s,j as a,m as o}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Архитектура и среда выполнения","description":"","frontmatter":{},"headers":[],"relativePath":"ru/architecture.md","filePath":"ru/architecture.md","lastUpdated":1780001723000}'),d={name:"ru/architecture.md"};function l(t,e,c,n,p,r){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="архитектура-и-среда-выполнения" tabindex="-1">Архитектура и среда выполнения <a class="header-anchor" href="#архитектура-и-среда-выполнения" aria-label="Permalink to &quot;Архитектура и среда выполнения&quot;">​</a></h1><p>Эта страница описывает backend, frontend, runtime dependencies и поведение логирования.</p><h2 id="архитектура" tabindex="-1">Архитектура <a class="header-anchor" href="#архитектура" aria-label="Permalink to &quot;Архитектура&quot;">​</a></h2><p>Backend package находится в <code>src/dj_track_similarity/</code>.</p><ul><li><code>cli.py</code> предоставляет Typer CLI <code>dj-sim</code>.</li><li><code>api.py</code> создает FastAPI app и REST endpoints.</li><li><code>database.py</code> отвечает за доступ к SQLite и все database mutations.</li><li><code>db_schema.py</code> определяет текущую SQLite-схему и validation.</li><li><code>scanner.py</code> сканирует папки и читает Mutagen metadata.</li><li><code>scan_jobs.py</code>, <code>analysis_jobs.py</code>, <code>sonara_jobs.py</code>, <code>genre_jobs.py</code>, <code>classifier_jobs.py</code> и <code>tags.py</code> управляют cancellable jobs и status objects.</li><li><code>audio_loader.py</code> предоставляет общий native-first audio loading.</li><li><code>sonara_features.py</code> извлекает сфокусированный набор Sonara playlist features.</li><li><code>sonara_similarity.py</code> и <code>sonara_similarity_scoring.py</code> ранжируют похожесть Sonara features.</li><li><code>embedding.py</code> содержит MERT и CLAP embedding adapters.</li><li><code>genres.py</code> содержит MAEST genre adapter.</li><li><code>classifier_scoring.py</code> загружает promoted classifier artifacts и оценивает feature-complete tracks.</li><li><code>search.py</code> выполняет similarity search в embedding space.</li><li><code>exporter.py</code> пишет M3U и CSV outputs.</li><li><code>runtime.py</code> выбирает <code>auto</code>, <code>cpu</code> или <code>cuda</code> для PyTorch tasks.</li><li><code>dependencies.py</code> проверяет runtime dependencies, например <code>ffmpeg</code>.</li><li><code>logging_config.py</code> настраивает rotating file logs.</li></ul><p>Frontend находится в <code>frontend/src/</code>.</p><ul><li><code>api.ts</code> зеркалит FastAPI contract.</li><li><code>App.tsx</code> координирует app state и workflows.</li><li><code>LibraryPanel.tsx</code> содержит scan, refresh, analysis, reset и clear controls.</li><li><code>TrackPanel.tsx</code>, <code>TrackRows.tsx</code> и <code>TrackMetadataDialog.tsx</code> показывают rows библиотеки и details треков.</li><li><code>SearchPlaylistPanel.tsx</code> содержит tabs SONARA, MERT, CLAP и CLASS, а также export controls.</li></ul><h2 id="runtime-dependencies" tabindex="-1">Runtime dependencies <a class="header-anchor" href="#runtime-dependencies" aria-label="Permalink to &quot;Runtime dependencies&quot;">​</a></h2><p>Основные runtime dependencies объявлены в <code>pyproject.toml</code>:</p><ul><li><code>numpy&gt;=1.26,&lt;2.0</code></li><li><code>mutagen</code></li><li><code>pydantic</code></li><li><code>typer</code></li><li><code>fastapi</code></li><li><code>uvicorn</code></li><li><code>joblib</code></li></ul><p>Optional groups:</p><ul><li><code>sonara</code>: устанавливает поддержку Sonara.</li><li><code>ml</code>: устанавливает синхронизированный стек PyTorch/Torchaudio/Torchvision/ TorchCodec, Transformers, Hugging Face Hub, LAION-CLAP и MAEST.</li><li><code>rhythm-lab</code>: устанавливает scikit-learn для локального обучения классификаторов и benchmarking в Rhythm Lab.</li><li><code>dev</code>: устанавливает pytest и Ruff.</li></ul><p><code>ffmpeg</code> требуется для надежного запуска сервера и декодирования аудио. Он может находиться через <code>PATH</code> или задаваться переменной:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DJ_TRACK_SIMILARITY_FFMPEG</span></span></code></pre></div><p>Проверенный Windows CUDA stack:</p><ul><li>PyTorch <code>2.11.0</code></li><li>Torchaudio <code>2.11.0</code></li><li>Torchvision <code>0.26.0</code></li><li>TorchCodec <code>0.13.0</code></li><li>NumPy <code>&gt;=1.26,&lt;2.0</code></li><li>PyTorch wheel index <code>https://download.pytorch.org/whl/cu130</code></li></ul><p>Установите matching CUDA wheels из официального PyTorch wheel index перед установкой остальных ML dependencies:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchvision</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchaudio</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torchcodec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Используйте <code>.[sonara,ml,rhythm-lab,dev]</code>, если та же среда будет обучать Rhythm Lab classifier profiles.</p><p>На Windows TorchCodec-backed Torchaudio decoding требует shared build FFmpeg с DLL в <code>PATH</code>, а не только статический <code>ffmpeg.exe</code>. Portable tools setup должен использовать GyanD <code>ffmpeg 8.1.1-full_build-shared</code> или совместимую структуру <code>full_build-shared</code>, например:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\ffmpeg.exe</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avcodec-*.dll</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avformat-*.dll</span></span></code></pre></div><h2 id="логирование" tabindex="-1">Логирование <a class="header-anchor" href="#логирование" aria-label="Permalink to &quot;Логирование&quot;">​</a></h2><p>Runtime file logging по умолчанию пишет в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dj-track-similarity.log</span></span></code></pre></div><p>Лог ротируется ежедневно в полночь и хранит один rotated day. INFO-level startup, completion, warning и error summaries пишутся по умолчанию. Успешные per-track job events агрегируются и не пишутся в file log, если detailed logging не включен.</p><p>Environment variables:</p><ul><li><code>DJ_TRACK_SIMILARITY_LOG</code>: путь file log.</li><li><code>DJ_TRACK_SIMILARITY_LOG_LEVEL</code>: <code>debug</code>, <code>info</code>, <code>warning</code>, <code>error</code> или <code>critical</code>.</li><li><code>DJ_TRACK_SIMILARITY_LOG_TRACK_EVENTS</code>: установите <code>1</code>, <code>true</code>, <code>yes</code> или <code>on</code>, чтобы писать успешные per-track job events.</li></ul><p>Сервер также поддерживает <code>--log-level</code> и <code>--log-track-events</code>.</p><p>CLI analysis commands во время работы печатают live one-line progress display. Строка перерисовывается на месте и включает progress bar, percentage, <code>processed/total</code>, <code>analyzed</code>, <code>failed</code>, примерный <code>tracks/s</code> и estimated remaining time. Это console-only progress для CLI process, который запустил job; он не подключается к jobs, стартовавшим из web UI/server process.</p><p>CLI analysis commands могут писать diagnostic timing lines в file log, если передан <code>--diagnostics</code> или установлено <code>DJ_TRACK_SIMILARITY_ANALYSIS_DIAGNOSTICS=1</code>. Они включают batch-level <code>prepare_seconds</code>, <code>decode_seconds</code>, <code>inference_seconds</code>, <code>save_seconds</code>, <code>total_seconds</code>, <code>tracks_per_second</code>, track count и window count для MERT/CLAP и MAEST. Sonara diagnostics логирует per-track <code>total_seconds</code> и <code>tracks_per_second</code>, потому что внутренние decode и feature extraction выполняются внутри Sonara. Audio loading также логирует decoder fallback details по path: failed decoders вроде <code>torchaudio</code>, <code>wave</code> или <code>ffmpeg</code>, их error text и fallback decoder, который в итоге сработал. Это diagnostic logging выключено по умолчанию.</p>`,30)])])}const g=i(d,[["render",l]]);export{k as __pageData,g as default};
